const device = { identifiers: ['highland_garage_bay_one'] };
const fullDevice = {
    ...device,
    name: 'Garage Door Bay One',
    model: 'GDO blaQ',
    manufacturer: 'Konnected'
};

const configs = [
    {
        topic: 'homeassistant/cover/highland_garage_bay_one/door/config',
        payload: {
            name: 'Garage Door',
            unique_id: 'highland_garage_bay_one_door',
            device_class: 'garage',
            state_topic: 'highland/state/garage/bay_one/door',
            command_topic: 'highland/command/garage/bay_one/door',
            value_template: '{{ value_json.state }}',
            position_topic: 'highland/state/garage/bay_one/door',
            position_template: '{{ (value_json.position * 100) | int }}',
            set_position_topic: 'highland/command/garage/bay_one/door',
            set_position_template: '{"action": "set_position", "position": {{ position / 100.0 }}}',
            payload_open: '{"action": "open"}',
            payload_close: '{"action": "close"}',
            payload_stop: '{"action": "stop"}',
            state_open: 'OPEN',
            state_closed: 'CLOSED',
            optimistic: false,
            retain: false,
            device: fullDevice
        }
    },
    {
        topic: 'homeassistant/light/highland_garage_bay_one/light/config',
        payload: {
            name: 'Garage Light',
            unique_id: 'highland_garage_bay_one_light',
            schema: 'json',
            state_topic: 'highland/state/garage/bay_one/light',
            command_topic: 'highland/command/garage/bay_one/light',
            optimistic: false,
            retain: false,
            device
        }
    },
    {
        topic: 'homeassistant/lock/highland_garage_bay_one/remote_lock/config',
        payload: {
            name: 'Remote Lock',
            unique_id: 'highland_garage_bay_one_remote_lock',
            device_class: 'lock',
            state_topic: 'highland/state/garage/bay_one/remote_lock',
            command_topic: 'highland/command/garage/bay_one/remote_lock',
            value_template: '{{ value_json.state }}',
            payload_lock: '{"action": "lock"}',
            payload_unlock: '{"action": "unlock"}',
            state_locked: 'LOCKED',
            state_unlocked: 'UNLOCKED',
            optimistic: false,
            retain: false,
            device
        }
    },
    {
        topic: 'homeassistant/binary_sensor/highland_garage_bay_one/obstruction/config',
        payload: {
            name: 'Obstruction',
            unique_id: 'highland_garage_bay_one_obstruction',
            device_class: 'problem',
            state_topic: 'highland/state/garage/bay_one/obstruction',
            value_template: '{{ value_json.state }}',
            payload_on: 'ON',
            payload_off: 'OFF',
            device
        }
    },
    {
        topic: 'homeassistant/binary_sensor/highland_garage_bay_one/motor/config',
        payload: {
            name: 'Motor',
            unique_id: 'highland_garage_bay_one_motor',
            state_topic: 'highland/state/garage/bay_one/motor',
            value_template: '{{ value_json.state }}',
            payload_on: 'ON',
            payload_off: 'OFF',
            device
        }
    },
    {
        topic: 'homeassistant/sensor/highland_garage_bay_one/openings/config',
        payload: {
            name: 'Opening Count',
            unique_id: 'highland_garage_bay_one_openings',
            state_topic: 'highland/state/garage/bay_one/openings',
            value_template: '{{ value_json.count }}',
            device
        }
    }
];

for (let i = 0; i < configs.length - 1; i++) {
    node.send({
        topic: configs[i].topic,
        payload: JSON.stringify(configs[i].payload)
    });
}

msg.topic = configs[configs.length - 1].topic;
msg.payload = JSON.stringify(configs[configs.length - 1].payload);
return msg;

if (!isValidJSON(msg.payload)) {
    return null;
}

msg.payload = JSON.parse(msg.payload);

const p = msg.payload;

// Only process known entities
const topicMap = {
    'cover-garage_door':       'highland/state/garage/bay_one/door',
    'light-garage_light':      'highland/state/garage/bay_one/light',
    'lock-lock':               'highland/state/garage/bay_one/remote_lock',
    'binary_sensor-obstruction': 'highland/state/garage/bay_one/obstruction',
    'binary_sensor-motor':     'highland/state/garage/bay_one/motor',
    'sensor-garage_openings':  'highland/state/garage/bay_one/openings'
};

if (!topicMap[p.id]) {
    return null;
} 

// Track last_direction for Smart Reversing (cover only)
if (p.id === 'cover-garage_door') {
    if (p.current_operation === 'OPENING') {
        flow.set('garage_last_direction', 'OPENING');
    } else if (p.current_operation === 'CLOSING') {
        flow.set('garage_last_direction', 'CLOSING');
    }
}

// Build state payload
const payload = {
    timestamp: new Date().toISOString(),
    source: 'garage_bridge',
    state: p.state
};

// Add entity-specific fields
if (p.id === 'cover-garage_door') {
    payload.current_operation = p.current_operation;
    payload.position = p.position;
}
if (p.id === 'sensor-garage_openings') {
    payload.count = p.value;
}
if (p.id === 'light-garage_light') {
    payload.color_mode = p.color_mode;
}

msg.topic = topicMap[p.id];
msg.payload = JSON.stringify(payload);
msg.retain = true;
msg.qos = 1;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({ fill: 'green', shape: 'dot', text: formatStatus(`${p.id}: ${p.state}`) });

return msg;

function isValidJSON(str) {
  if (typeof str !== 'string') return false; // Must be a string to be JSON
  try {
    const result = JSON.parse(str);
    // Optional: Ensure it's an object or array, as numbers/booleans are technically valid JSON
    return (typeof result === 'object' && result !== null);
  } catch (e) {
    return false;
  }
}

const payload = typeof msg.payload === 'string'
    ? JSON.parse(msg.payload)
    : msg.payload;

const topic = msg.topic;
const action = topic === 'highland/command/garage/bay_one/light'
    ? (payload.state === 'ON' ? 'turn_on' : 'turn_off')
    : payload.action;

const blaqIp = '192.168.1.71';

// Route based on topic and action
const routes = {
    'highland/command/garage/bay_one/door': {
        'open': `/cover/garage_door/open`,
        'close': `/cover/garage_door/close`,
        'stop': `/cover/garage_door/stop`,
        'toggle': `/cover/garage_door/toggle`,
        'set_position': `/cover/garage_door/set`
    },
    'highland/command/garage/bay_one/light': {
        'turn_on': `/light/garage_light/turn_on`,
        'turn_off': `/light/garage_light/turn_off`,
        'toggle': `/light/garage_light/toggle`
    },
    'highland/command/garage/bay_one/remote_lock': {
        'lock': `/lock/lock/lock`,
        'unlock': `/lock/lock/unlock`
    }
};

const topicRoutes = routes[topic];
if (!topicRoutes) {
    node.warn(`Unknown command topic: ${topic}`);
    return null;
}

const path = topicRoutes[action];
if (!path) {
    node.warn(`Unknown action '${action}' for topic ${topic}`);
    return null;
}

msg.url = `http://${blaqIp}${path}`;
msg.method = 'POST';
msg.payload = '';

// Handle set_position — needs query param
if (action === 'set_position') {
    msg.url += `?position=${payload.position}`;
}

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({ fill: 'blue', shape: 'dot', text: formatStatus(`${action} → ${path}`) });

return msg;

if (msg.statusCode !== 200) {
    node.warn(`blaQ command failed: ${msg.statusCode} — ${msg.payload}`);
}
const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({ fill: msg.statusCode === 200 ? 'green' : 'red', shape: 'dot', 
    text: formatStatus(`${msg.statusCode}`) });
return null;
